import React, { Component } from 'react';
import {
  StyleSheet,
  View,
  Text
} from 'react-native';
import Share, {ShareSheet, Button} from 'react-native-share';
import { ShareDialog } from 'react-native-fbsdk';
import { AppInstalledChecker, CheckPackageInstallation } from 'react-native-check-app-install';

import lng from './Language';

export default class ShareApp extends Component {
  constructor(props) {
    super(props);
    this.state = {
      visible: false,
      appUrl: '',
      lngShareSub : '',
      lngBack : '',
      lngMessage : '',
      lngSubject : '',
      privateKey: ''
    }
  }


  async componentDidMount(){
   
    let shareAppLang = await lng.shareAppLang()
    let privateKLng = await lng.userInfoLang()

    this.setState({
      lngShareSub : this.props.privateKey?shareAppLang.lngSharePri:shareAppLang.lngShareSub,
      lngBack : shareAppLang.lngBack,
      lngMessage : shareAppLang.lngMessage,
      lngSubject : shareAppLang.lngSubject,
      privateKey: this.props.privateKey? privateKLng.lngPriCode + ' ' +this.props.privateKey:''
    })
 
    this.setState(
      { visible : this.props.shareVisible ,
        appUrl: `Android:\nhttps://play.google.com/store/apps/details?id=com.solutionvalleyab.insec\nIOS:\nhttp://itunes.com/apps/SolutionValleyAB/insec`
      });

  }
  
  onCancel() {
    this.props.visibleFalse()
    this.setState({visible:false});
  }

  render() {
 
    let shareLinkContent = {
      contentType: 'link',
       contentUrl: `https://play.google.com/store/apps/details?id=com.solutionvalleyab.insec`,
       contentDescription: this.state.lngMessage,
    };

    let shareOptions = ''
    if (this.state.privateKey){
      shareOptions = {
        title: "Insec App",
        message: `${this.state.privateKey}\n\n${this.state.appUrl}`,
        subject: `${this.state.privateKey}` //  for email
      };
    }else{
      shareOptions = {
        title: "Insec App",
        message: `${this.state.lngMessage}\n\n${this.state.appUrl}`,
        subject: this.state.lngSubject //  for email
      };
    }
    
    if (this.props.shareVisible === false ) return <View ></View>
 
    return (

      <View style={styles.container}>

        <ShareSheet visible={this.props.shareVisible} onCancel={this.onCancel.bind(this)}>
          <Text style={ styles.textSub }>{ this.state.lngShareSub }</Text>
          <Button iconSrc={{ uri: TWITTER_ICON }}
                  onPress={()=>{
              this.onCancel();
              setTimeout(() => {
                Share.shareSingle(Object.assign(shareOptions, {
                  "social": "twitter"
                }));
              },300);
            }}>Twitter</Button>
          <Button iconSrc={{ uri: FACEBOOK_ICON }}
                  onPress={()=>{
                    ShareDialog.canShow(shareLinkContent).then(
                      function(canShow) {
                        if (canShow) {
                          return ShareDialog.show(shareLinkContent);
                        }
                      }
                    )
            }}>Facebook</Button>
          <Button iconSrc={{ uri: WHATSAPP_ICON }}
                  onPress={()=>{
                    AppInstalledChecker
                    .checkURLScheme('whatsapp') // omit the :// suffix
                    .then((isInstalled) => {
                      if(isInstalled){
                          this.onCancel();
                          setTimeout(() => {
                            Share.shareSingle(Object.assign(shareOptions, {
                              "social": "whatsapp"
                            })
                            
                            ).catch((e)=>{console.log(e)});
                          },300);                      
                      }
                    })
            }}>Whatsapp</Button>
          <Button iconSrc={{ uri: EMAIL_ICON }}
                  onPress={()=>{
               
                      this.onCancel();
                      setTimeout(() => {
                        Share.shareSingle(Object.assign(shareOptions, {
                          "social": "email"
                        }));
                      },300);
            }}>Email</Button>
          <Button iconSrc={{ uri: MORE_ICON }}
            onPress={()=>{
              this.onCancel();
              setTimeout(() => {
                Share.open(shareOptions)
              },300);
            }}>More</Button>
          <Button
          onPress={()=>{
            this.onCancel();
          }}>
          { this.state.lngBack }</Button>
        </ShareSheet>
      </View>
    );
  }
}
 
const styles = StyleSheet.create({
  container: {
    backgroundColor:'black',
    marginTop: -365,
    margin:5,
    height: 360,
    justifyContent: 'center',
    alignItems: 'center',
    backgroundColor: '#F5FCFF',
   
  },
  textSub: {
    margin:10,
    fontSize:14,
    fontWeight: 'bold'
  }
});
 
//  more icon
const MORE_ICON = "data:image/png;base64,";


//  twitter icon
const TWITTER_ICON = "data:image/png;base64,";
 
//  facebook icon
const FACEBOOK_ICON = "data:image/png;base64,";
 
//  whatsapp icon
const WHATSAPP_ICON = "data:image/png;base64,";
 
//  email icon
const EMAIL_ICON = "data:image/png;base64,";
 